#include <stdio.h>
#include <stdbool.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N; scanf("%d", &N);
        bool ok = true;
        for(int i=1;i<=N;i++){
            int b; scanf("%d", &b);
            if(i % b != 0) ok = false;
        }
        puts(ok?"YES":"NO");
    }
    return 0;
}

