#!/usr/bin/env python3
import sys
def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out = []
    for _ in range(T):
        N = int(next(it))
        ok = True
        for i in range(1, N+1):
            b = int(next(it))
            if i % b != 0:
                ok = False
        out.append('YES' if ok else 'NO')
    sys.stdout.write('\n'.join(out))
if __name__ == "__main__":
    solve()

